class Solution:
    def minOperations(self, nums):
        import sys
        sys.setrecursionlimit(300000)
        def solve(arr):
            # arr: list of positive ints (a maximal nonzero segment)
            if not arr:
                return 0
            m = min(arr)
            ops = 1
            piece = []
            for x in arr:
                if x == m:
                    ops += solve(piece)
                    piece = []
                else:
                    piece.append(x)
            ops += solve(piece)
            return ops
        total = 0
        seg = []
        for x in nums:
            if x == 0:
                total += solve(seg)
                seg = []
            else:
                seg.append(x)
        total += solve(seg)
        return total

