class Solution:
    def minOperations(self, nums):
        stack = []
        ans = 0
        for x in nums:
            if x == 0:
                stack.clear()
                continue
            while stack and stack[-1] > x:
                stack.pop()
            if stack and stack[-1] == x:
                continue
            stack.append(x)
            ans += 1
        return ans

