var minOperations = function(nums) {
    const stack = [];
    let ans = 0;
    for (const x of nums) {
        if (x === 0) { stack.length = 0; continue; }
        while (stack.length && stack[stack.length - 1] > x) stack.pop();
        if (stack.length && stack[stack.length - 1] === x) continue;
        stack.push(x);
        ans++;
    }
    return ans;
};
